    function normalizeVoiceCommandText(text) {
        return normalizeSpace(text || '')
            .toLowerCase()
            .normalize('NFD')
            .replace(/[\u0300-\u036f]/g, '')
            .replace(/[’']/g, ' ')
            .replace(/[^a-z0-9]+/g, ' ')
            .replace(/\s+/g, ' ')
            .trim();
    }

    function parseVoiceCommand(text) {
        const command = normalizeVoiceCommandText(text);
        let match = null;

        match = command.match(/^command send (on|off)$/);
        if (match) {
            return { type: 'send', value: match[1] === 'on' };
        }

        match = command.match(/^command (global|full|full flow) (on|off|yes|no)$/);
        if (match) {
            return { type: 'global', value: match[2] === 'on' || match[2] === 'yes' };
        }

        match = command.match(/^command (tos|time of silence|new transcription) (on|off|yes|no)$/);
        if (match) {
            return { type: 'tos', value: match[2] === 'on' || match[2] === 'yes' };
        }

        match = command.match(/^command trigger read(?: aloud| a loud| a lot| a load| allowed| alloud| out|aloud) (yes|no|on|off)$/);
        if (match) {
            return { type: 'triggerReadAloud', value: match[1] === 'yes' || match[1] === 'on' };
        }

        return null;
    }

    async function handleVoiceCommandTranscript(text) {
        const parsed = parseVoiceCommand(text);
        if (!parsed) {
            return false;
        }

        const originalHash = hashText(text);
        clearComposerText();
        pendingSendAfterV = false;
        vClickedThisCycle = false;
        sendAttemptedThisCycle = false;
        pendingSendStartedAt = 0;
        lastComposerText = '';
        composerStableSince = 0;
        lastSentHash = originalHash;
        resetSilenceState();
        stopAudioMonitor();

        if (parsed.type === 'send') {
            await setSendEnabledState(parsed.value, parsed.value ? 'Command: SEND ON' : 'Command: SEND OFF');
            if (state.enabled) {
                armNextCycleAfterSend(parsed.value ? 'Command SEND ON / waiting ReadAloud' : 'Command SEND OFF / waiting ReadAloud');
            } else {
                cycleDone = true;
            }
            return true;
        }

        if (parsed.type === 'triggerReadAloud') {
            await setTriggerReadAloudEnabledState(parsed.value, parsed.value ? 'Command: Trigger YES' : 'Command: Trigger NO');
            if (state.enabled) {
                armNextCycleAfterSend(parsed.value ? 'Command Trigger YES / waiting ReadAloud' : 'Command Trigger NO / waiting ReadAloud');
            } else {
                cycleDone = true;
            }
            return true;
        }

        if (parsed.type === 'global') {
            await setFullFlowEnabled(parsed.value, parsed.value ? 'Command: Full Flow YES' : 'Command: Full Flow NO');
            return true;
        }

        if (parsed.type === 'tos') {
            await setEnabled(parsed.value);
            setStatus(parsed.value ? 'Command: TOS YES' : 'Command: TOS NO');
            return true;
        }

        return false;
    }

