    function setupDrag(handle, target) {
        let offsetX = 0;
        let offsetY = 0;
        let startX = 0;
        let startY = 0;

        handle.addEventListener('mousedown', (event) => {
            if (event.button !== 0) {
                return;
            }
            if (closestOrNull(event.target, 'button') && !target.classList.contains('cgas-mini-minimized')) {
                return;
            }
            dragging = true;
            dragMoved = false;
            const rect = target.getBoundingClientRect();
            startX = event.clientX;
            startY = event.clientY;
            offsetX = event.clientX - rect.left;
            offsetY = event.clientY - rect.top;
            event.preventDefault();
        }, true);

        window.addEventListener('mousemove', (event) => {
            if (!dragging) {
                return;
            }
            if (Math.abs(event.clientX - startX) > 3 || Math.abs(event.clientY - startY) > 3) {
                dragMoved = true;
            }
            const maxLeft = Math.max(0, window.innerWidth - target.offsetWidth - 4);
            const maxTop = Math.max(0, window.innerHeight - target.offsetHeight - 4);
            const left = Math.min(maxLeft, Math.max(4, event.clientX - offsetX));
            const top = Math.min(maxTop, Math.max(4, event.clientY - offsetY));
            target.style.left = left + 'px';
            target.style.top = top + 'px';
            target.style.right = 'auto';
            target.style.bottom = 'auto';
            state.left = left;
            state.top = top;
            event.preventDefault();
        }, true);

        window.addEventListener('mouseup', (event) => {
            if (!dragging) {
                return;
            }
            dragging = false;
            if (dragMoved) {
                suppressClickUntil = now() + 320;
                event.preventDefault();
                event.stopPropagation();
            }
            saveStatePatch({ left: state.left, top: state.top });
        }, true);

        target.addEventListener('click', (event) => {
            if (now() < suppressClickUntil) {
                event.preventDefault();
                event.stopPropagation();
            }
        }, true);
    }

    function centerWidgetInViewport(persist) {
        if (!widget) {
            return;
        }
        widget.classList.remove('cgas-mini-hidden');
        const width = widget.offsetWidth || (state.minimized ? 42 : 76);
        const height = widget.offsetHeight || (state.minimized ? 42 : 180);
        const left = Math.max(4, Math.round((window.innerWidth - width) / 2));
        const top = Math.max(4, Math.round((window.innerHeight - height) / 2));
        widget.style.left = left + 'px';
        widget.style.top = top + 'px';
        widget.style.right = 'auto';
        widget.style.bottom = 'auto';
        state.left = left;
        state.top = top;
        if (persist) {
            saveStatePatch({ left: state.left, top: state.top });
        }
    }

    async function positionMaxiAtRequestedReloadAnchor(persist) {
        if (!widget) {
            return;
        }

        state.minimized = false;
        state.maximized = true;
        state.visible = true;
        updateWidget();

        await new Promise((resolve) => window.requestAnimationFrame(() => {
            window.requestAnimationFrame(resolve);
        }));

        const width = widget.offsetWidth || 148;
        const height = widget.offsetHeight || 520;
        const rightMargin = 34;
        const bottomMargin = 18;
        const left = Math.max(4, Math.round(window.innerWidth - width - rightMargin));
        const top = Math.max(4, Math.round(window.innerHeight - height - bottomMargin));

        widget.style.left = left + 'px';
        widget.style.top = top + 'px';
        widget.style.right = 'auto';
        widget.style.bottom = 'auto';
        state.left = left;
        state.top = top;

        if (persist) {
            await saveStatePatch({
                left: state.left,
                top: state.top,
                minimized: false,
                maximized: true,
                visible: true
            });
        }
    }

    function ensureWidgetInsideViewport(persist) {
        if (!widget || !state.visible || state.left === null || state.top === null) {
            return;
        }
        const width = widget.offsetWidth || (state.minimized ? 42 : 76);
        const height = widget.offsetHeight || (state.minimized ? 42 : 180);
        const maxLeft = Math.max(4, window.innerWidth - width - 4);
        const maxTop = Math.max(4, window.innerHeight - height - 4);
        const outside = state.left < 4 || state.top < 4 || state.left > maxLeft || state.top > maxTop;
        if (!outside) {
            return;
        }
        centerWidgetInViewport(persist);
    }

    async function setWidgetVisible(nextVisible, centerOnShow) {
        state.visible = Boolean(nextVisible);
        if (state.visible && centerOnShow) {
            state.minimized = false;
            await saveStatePatch({ visible: true, minimized: false });
            updateWidget();
            centerWidgetInViewport(true);
            setStatus('Visible');
            return;
        }
        await saveStatePatch({ visible: state.visible });
        updateWidget();
    }

    async function toggleWidgetFromExtensionAction() {
        if (!widget) {
            createWidget();
        }

        const currentlyVisible = Boolean(state.visible && widget && !widget.classList.contains('cgas-mini-hidden'));

        if (!currentlyVisible) {
            state.visible = true;
            await saveStatePatch({ visible: true });
            updateWidget();
            setStatus('Visible');
            return { visible: true, restoredPosition: true };
        }

        state.visible = false;
        await saveStatePatch({ visible: false });
        updateWidget();
        setStatus('Hidden');
        return { visible: false, restoredPosition: false };
    }

    function installRuntimeMessageListener() {
        try {
            if (window.__CGAS_ACTION_TOGGLE_LISTENER_INSTALLED__) {
                return;
            }
            if (typeof chrome === 'undefined' || !chrome || !chrome.runtime || !chrome.runtime.onMessage) {
                return;
            }
            window.__CGAS_ACTION_TOGGLE_LISTENER_INSTALLED__ = true;
            chrome.runtime.onMessage.addListener((message, sender, sendResponse) => {
                if (!message || message.type !== 'CGAS_ACTION_TOGGLE_WIDGET') {
                    return false;
                }
                toggleWidgetFromExtensionAction()
                    .then((result) => sendResponse({ ok: true, result }))
                    .catch((error) => {
                        logRuntimeError('extension action toggle failed', error);
                        sendResponse({ ok: false, error: error && error.message ? error.message : String(error) });
                    });
                return true;
            });
        } catch (error) {
            logRuntimeError('installRuntimeMessageListener failed', error);
        }
    }

